#ifndef ESEC_AES_BASICS_HEADER
#define ESEC_AES_BASICS_HEADER

#include <stdint.h>
#include <stddef.h>

#include "esec_errors.h"
#include "esec_symm_basics.h"

/** Size of the IV for different AES algorithms **/
#define ESEC_AES_ECB_IV_SIZE 16
#define ESEC_AES_CBC_IV_SIZE 16
#define ESEC_AES_CTR_IV_SIZE 16
#define ESEC_AES_CFB_IV_SIZE 16
#define ESEC_AES_OFB_IV_SIZE 16
#define ESEC_AES_XTS_IV_SIZE 16
#define ESEC_AES_GCM_IV_SIZE 12

/* Block size for AES algorithms. */
#define ESEC_AES_BLOCK_SIZE 16

/** Size of the authentication tag generated by the AES GCM algorithm **/
#define ESEC_TAG_SIZE_AES_GCM 16

/** Size of the authentication tag generated by the AES CMAC algorithm **/
#define ESEC_TAG_SIZE_AES_CMAC 16

enum esec_aes_mode {
    ESEC_AES_CBC = 0x02,
    ESEC_AES_CTR = 0x03,
    ESEC_AES_CFB = 0x04,
    ESEC_AES_OFB = 0x05,
    ESEC_AES_XTS = 0x08
};

struct esec_aes_state {
    /* Stores the eSecure command. */
    uint32_t command;
    /* Saved context between several calls. */
    uint8_t context[16];
    /* Saved key. */
    struct esec_skey skey;
};

#endif
